// ===== Helpers =====
const normalize = (str = "") =>
  str
    .toLowerCase()
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "") // remove diacritics
    .replace(/ı/g, "i")              // Turkish dotless i -> i
    .replace(/ş/g, "s")              // ş -> s
    .replace(/\s+/g, " ")
    .trim();

const stripPdfExt = (name = "") => name.replace(/\.pdf$/i, "").trim();

/**
 * يحذف الكلمات/العِبارات الدلالية مثل:
 * - limited / limited company / ltd
 * - tasfiye halinde
 * - şahsi / şahsı / şahıs / sahsi / sahis
 * - tax payer / tax payers
 *
 * التنفيذ مبني على "توكينات" وليس \b لتجنب مشاكل يونيكود.
 */
const cleanCompanyName = (raw = "") => {
  // شيل الامتداد والنِّقاط المنفصلة
  let base = stripPdfExt(raw)
    .replace(/\s*\.\s*/g, " ")
    .replace(/\s+/g, " ")
    .trim();

  // نفصل إلى توكينات بناءً على مسافات/فواصل/شرطات... (نحتفظ بالمقسِّم لإعادة البناء)
  const splitter = /([ \t,؛;:()|/\-–—]+)/; // مجموعة "التقسيم" تُعيد المقسّم أيضًا
  const parts = base.split(splitter);

  // سنبني ناتجًا جديدًا بحذف التوكينات المحظورة
  const out = [];
  // نحتاج النظر للأمام للتراكيب ثنائية الكلمات
  for (let i = 0; i < parts.length; i++) {
    const token = parts[i];

    // لو كان هذا مقسِّم (مسافات/فواصل...) مرّره مؤقتًا، القرار يكون على الكلمة
    if (splitter.test(token)) {
      out.push(token);
      continue;
    }

    const nTok = normalize(token); // sahsi, limited, tasfiye, ...
    const nextToken = parts[i + 2] ?? "";      // مابعد المقسّم التالي
    const nextSep   = parts[i + 1] ?? "";      // المقسّم بين الكلمتين
    const nNextTok  = normalize(nextToken);

    // قوائم الكلمات المفردة المطلوب حذفها
    const singleStops = new Set([
      "limited", "ltd", "company", // "company" وحدها تُحذف إن جت منسابة في الآخر
      "tasfiye", "halinde",
      "sahsi", "sahis",            // تغطّي şahsi / şahsı / şahıs بعد normalize
      "tax", "payer", "payers"
    ]);

    // تراكيب ثنائية نُزيلها معًا (token + nextToken)
    const twoWordStops = new Set([
      "limited company",
      "tasfiye halinde",
      "tax payer",
      "tax payers"
    ]);

    // هل هذه تركيبة ثنائية؟
    const isTwoWordCombo =
      nextSep && splitter.test(nextSep) &&
      twoWordStops.has(`${nTok} ${nNextTok}`);

    if (isTwoWordCombo) {
      // تخطي: الكلمة الحالية + المقسّم + الكلمة التالية
      i += 2; // نقفز فوق nextSep و nextToken
      // لو نتج فاصل مزدوج، نُعالج لاحقًا بالتنظيف
      continue;
    }

    // هل هي كلمة مفردة ممنوعة؟
    if (singleStops.has(nTok)) {
      // لا نضيفها
      continue;
    }

    // خلاف ذلك، نُضيف التوكين كما هو
    out.push(token);
  }

  // نظّف: إزالة الفواصل/الشرطات المتراكمة والأطراف
  let cleaned = out.join("")
    .replace(/\s+/g, " ")
    .replace(/\s*[,؛;:()|/\-–—]\s*$/g, "") // فاصل في آخر السطر
    .replace(/^[,؛;:()|/\-–—]\s*/g, "")    // فاصل في أول السطر
    .trim();

  return cleaned;
};

const classify = (name = "") => {
  const n = normalize(name);

  const isLimited =
    /\blimited\s+company\b/.test(n) ||
    /\blimited\b/.test(n) ||
    /\bltd\b/.test(n) ||
    /\btasfiye\s+halinde\b/.test(n);

  // بعد normalize تصبح كل صيغ şahsi → sahsi/sahis
  const isPersonal = /\bsahsi\b/.test(n) || /\bsahis\b/.test(n);

  if (isLimited) return { type: "Limited_Company", matched: "limited" };
  if (isPersonal) return { type: "personal_Company", matched: "personal" };
  return { type: "Taxpayers", matched: "other" };
};

// ===== Transform =====
return items.map((item) => {
  const fileName = item.json?.name ?? item.json?.fileName ?? "";
  const originalId = item.json?.id ?? item.json?.fileId ?? null;

  const { type: companyType, matched: matchedGroup } = classify(fileName);
  const companyName = cleanCompanyName(fileName);
  const normalizedName = normalize(companyName);

  return {
    json: {
      id: originalId,
      name: fileName,
      companyName,       // بدون şahsi/şahsı/şahıs + باقي المحددات
      normalizedName,
      companyType,       // Limited_Company | personal_Company | Taxpayers
      matchedGroup,      // "limited" | "personal" | "other"
    },
  };
});

