function normalizeText(text) {
  return text
    .toLowerCase()
    .normalize("NFD") // فصل الحروف عن الـ accents
    .replace(/[\u0300-\u036f]/g, "") // إزالة الـ accents
    .replace(/ı/g, "i") // استبدال الحروف التركية
    .replace(/ş/g, "s")
    .replace(/ğ/g, "g")
    .replace(/ü/g, "u")
    .replace(/ö/g, "o")
    .replace(/ç/g, "c")
    .trim();
}

const companies = $items("normalize Taxpayers sheet", 0, 0).map(i => i.json);
const taxFolders = $input.all().map(i => i.json);

const results = companies.map(company => {
  const companyNameNorm = normalizeText(company.newFolderName);
  const companyNormAlt = normalizeText(company.normalizedFolderName);

  const matchedFolder = taxFolders.find(folder => {
    const folderNameNorm = normalizeText(folder.name);
    return folderNameNorm === companyNameNorm || folderNameNorm === companyNormAlt;
  });

  return {
    json: {
      companyFolderId: company.id,
      companyName: company.name,
      parentFolderId: company.parentFolderId,
      taxFolderName: company.newFolderName,
      taxFolderId: matchedFolder ? matchedFolder.id : null,
      companyType: company.companyType,
      taxFolderExists: !!matchedFolder,
      normalizedCompanyName: company.normalizedCompanyName,
      normalizedFolderName: company.normalizedFolderName
    }
  };
});

return results;

